import React from 'react';
import './Login.css';
// Import your new logo file
import streamStackLogo from './assets/logo.png'; 

const Login = () => {
  return (
    <div className="login-container">
      <div className="login-card">
        <div className="logo-section">
          {/* Replace the old icon with your logo.png */}
          <img 
            src={streamStackLogo} 
            alt="StreamStack Logo" 
            className="app-logo" 
          />
          <h1 className="app-title">StreamStack</h1>
          <p className="app-subtitle">Your Personal Movie Manager</p>
        </div>

        <form className="login-form">
          <div className="input-group">
            <label>Email / Username</label>
            <input type="email" placeholder="Enter your email" required />
          </div>
          
          <div className="input-group">
            <label>Password</label>
            <input type="password" placeholder="Enter your password" required />
          </div>

          <button type="submit" className="login-button">Login</button>
        </form>
      </div>
    </div>
  );
};

export default Login;
